const express = require('express');
const { Pool } = require('pg');
const cors = require('cors');
const bcrypt = require('bcrypt');
const jwt = require('jsonwebtoken');

const app = express();
const JWT_SECRET = 'letov_secret_key_2024';

app.use(cors({
    origin: '*',
    methods: ['GET', 'POST', 'PUT', 'DELETE', 'OPTIONS'],
    allowedHeaders: ['Content-Type', 'Authorization']
}));

app.use(express.json());

const pool = new Pool({
    host: 'db',
    user: 'postgres',
    password: 'postgres',
    database: 'letov',
    port: 5432
});

pool.connect((err, client, release) => {
    if (err) {
        console.error('Ошибка подключения к БД:', err.stack);
    } else {
        console.log('✅ Подключено к PostgreSQL');
        release();
    }
});

// Middleware для проверки токена
const authenticateToken = (req, res, next) => {
    const authHeader = req.headers['authorization'];
    const token = authHeader && authHeader.split(' ')[1];
    
    if (!token) {
        return res.status(401).json({ error: 'Требуется авторизация' });
    }
    
    jwt.verify(token, JWT_SECRET, (err, user) => {
        if (err) {
            return res.status(403).json({ error: 'Недействительный токен' });
        }
        req.user = user;
        next();
    });
};

const isAdmin = (req, res, next) => {
    if (!req.user.isAdmin) {
        return res.status(403).json({ error: 'Доступ запрещён' });
    }
    next();
};

// ========== АВТОРИЗАЦИЯ ==========
app.post('/api/auth/register', async (req, res) => {
    const { username, email, password } = req.body;
    
    if (!username || !email || !password) {
        return res.status(400).json({ error: 'Все поля обязательны' });
    }
    
    try {
        const hashedPassword = await bcrypt.hash(password, 10);
        
        const result = await pool.query(
            'INSERT INTO users(username, email, password_hash) VALUES($1, $2, $3) RETURNING id, username, email, is_admin',
            [username, email, hashedPassword]
        );
        
        const token = jwt.sign({ 
            id: result.rows[0].id, 
            username: result.rows[0].username,
            isAdmin: result.rows[0].is_admin 
        }, JWT_SECRET, { expiresIn: '24h' });
        
        // Логируем активность
        await pool.query(
            'INSERT INTO user_activity(user_id, activity) VALUES($1, $2)',
            [result.rows[0].id, 'Зарегистрировался на сайте']
        );
        
        res.json({ 
            token, 
            user: {
                id: result.rows[0].id,
                username: result.rows[0].username,
                email: result.rows[0].email,
                isAdmin: result.rows[0].is_admin
            }
        });
    } catch (err) {
        console.error('Register error:', err);
        if (err.constraint === 'users_username_key') {
            res.status(400).json({ error: 'Имя пользователя уже занято' });
        } else if (err.constraint === 'users_email_key') {
            res.status(400).json({ error: 'Email уже используется' });
        } else {
            res.status(500).json({ error: 'Ошибка регистрации' });
        }
    }
});

app.post('/api/auth/login', async (req, res) => {
    const { username, password } = req.body;
    
    if (!username || !password) {
        return res.status(400).json({ error: 'Все поля обязательны' });
    }
    
    try {
        const result = await pool.query(
            'SELECT * FROM users WHERE username = $1',
            [username]
        );
        
        if (result.rows.length === 0) {
            return res.status(401).json({ error: 'Неверное имя пользователя или пароль' });
        }
        
        const user = result.rows[0];
        const validPassword = await bcrypt.compare(password, user.password_hash);
        
        if (!validPassword) {
            return res.status(401).json({ error: 'Неверное имя пользователя или пароль' });
        }
        
        // Обновляем last_login
        await pool.query('UPDATE users SET last_login = CURRENT_TIMESTAMP WHERE id = $1', [user.id]);
        
        // Логируем активность
        await pool.query(
            'INSERT INTO user_activity(user_id, activity) VALUES($1, $2)',
            [user.id, 'Вход в систему']
        );
        
        const token = jwt.sign({ 
            id: user.id, 
            username: user.username,
            isAdmin: user.is_admin 
        }, JWT_SECRET, { expiresIn: '24h' });
        
        res.json({ 
            token, 
            user: {
                id: user.id,
                username: user.username,
                email: user.email,
                isAdmin: user.is_admin
            }
        });
    } catch (err) {
        console.error('Login error:', err);
        res.status(500).json({ error: 'Ошибка входа' });
    }
});

// ========== ОТЗЫВЫ С РЕАКЦИЯМИ ==========
app.get('/api/reviews/:songId', async (req, res) => {
    const { songId } = req.params;
    try {
        const result = await pool.query(
            `SELECT r.*, u.username 
             FROM reviews r 
             JOIN users u ON r.user_id = u.id 
             WHERE r.song_id = $1 
             ORDER BY r.created_at DESC`,
            [songId]
        );
        
        const reviews = await Promise.all(result.rows.map(async (review) => {
            const reactionsResult = await pool.query(
                'SELECT reaction, COUNT(*) as count FROM review_reactions WHERE review_id = $1 GROUP BY reaction',
                [review.id]
            );
            
            const reactions = {};
            reactionsResult.rows.forEach(r => {
                reactions[r.reaction] = parseInt(r.count);
            });
            
            return {
                ...review,
                reactions
            };
        }));
        
        res.json(reviews);
    } catch (err) {
        console.error('GET /reviews error:', err);
        res.status(500).json({ error: 'Database error' });
    }
});

app.post('/api/reviews', authenticateToken, async (req, res) => {
    const { text, songId } = req.body;
    if (!text || text.trim() === '') {
        return res.status(400).json({ error: 'Text is required' });
    }
    try {
        const result = await pool.query(
            'INSERT INTO reviews(user_id, song_id, text) VALUES($1, $2, $3) RETURNING *',
            [req.user.id, songId, text.trim()]
        );
        
        const userResult = await pool.query('SELECT username FROM users WHERE id = $1', [req.user.id]);
        
        // Логируем активность
        await pool.query(
            'INSERT INTO user_activity(user_id, activity) VALUES($1, $2)',
            [req.user.id, `Оставил отзыв к песне ${songId}`]
        );
        
        res.json({ ...result.rows[0], username: userResult.rows[0].username, reactions: {} });
    } catch (err) {
        console.error('POST /reviews error:', err);
        res.status(500).json({ error: 'Database error' });
    }
});

app.post('/api/reviews/:id/react', authenticateToken, async (req, res) => {
    const { id } = req.params;
    const { reaction } = req.body;
    
    try {
        // UPSERT: вставляем или обновляем реакцию
        await pool.query(
            `INSERT INTO review_reactions(review_id, user_id, reaction) 
             VALUES($1, $2, $3) 
             ON CONFLICT (review_id, user_id) 
             DO UPDATE SET reaction = $3`,
            [id, req.user.id, reaction]
        );
        
        const reactionsResult = await pool.query(
            'SELECT reaction, COUNT(*) as count FROM review_reactions WHERE review_id = $1 GROUP BY reaction',
            [id]
        );
        
        const reactions = {};
        reactionsResult.rows.forEach(r => {
            reactions[r.reaction] = parseInt(r.count);
        });
        
        // Логируем активность
        await pool.query(
            'INSERT INTO user_activity(user_id, activity) VALUES($1, $2)',
            [req.user.id, `Поставил реакцию ${reaction} на отзыв #${id}`]
        );
        
        res.json({ reactions });
    } catch (err) {
        console.error('POST /reviews/:id/react error:', err);
        res.status(500).json({ error: 'Database error' });
    }
});

