app.get('/api/admin/stats', authenticateToken, isAdmin, async (req, res) => {
    try {
        const usersResult = await pool.query('SELECT COUNT(*) as total FROM users');
        const ordersResult = await pool.query('SELECT COUNT(*) as total, COALESCE(SUM(total), 0) as revenue FROM orders WHERE status = $1', ['completed']);
        const reviewsResult = await pool.query('SELECT COUNT(*) as total FROM reviews');
        
        res.json({
            users: parseInt(usersResult.rows[0].total),
            orders: parseInt(ordersResult.rows[0].total),
            revenue: parseInt(ordersResult.rows[0].revenue || 0),
            reviews: parseInt(reviewsResult.rows[0].total)
        });
    } catch (err) {
        console.error('GET /admin/stats error:', err);
        res.status(500).json({ error: 'Database error' });
    }
});

